UPDATE jobs SET user_contributed_json = '{"way":"전통건축기능원이 되려면 한국전통문화대학교 전통건축학과 등 전문 교육기관을 졸업하거나[1], 문화재청 인정 전통건축 기능 전수 교육을 이수해야 한다.[2] 도제식 전수를 통해 목공·석공·단청 등 특정 분야를 전문화하는 것이 일반적이며, 국가무형문화재 전수자 인정을 목표로 할 수도 있다.[3]","overviewSalary":{"sal":"경력에 따라 연봉 3,000만~5,000만 원 수준이며[1], 문화재 전문 기능원으로 인정받으면 상당한 프리미엄이 붙는다.[2]","source":"워크넷 직업정보, 커리어넷(2024)"},"overviewProspect":{"main":"문화재 보수·복원 수요는 꾸준히 유지되며[1], 전통건축 기능 인력의 고령화로 신진 기능원에 대한 수요가 증가하고 있다.[2]","source":"문화재청, 한국고용정보원(2024)"},"trivia":"한식 목구조는 못을 최소화하고 짜임(장부 맞춤)만으로 건물을 지어 수백 년을 견딘다.[1] 경복궁 광화문 복원(2010년)에는 약 300여 명의 전통건축 기능인이 참여해 3년간 수작업으로 완성했다.[2] 단청 안료는 금·은·주사·석청 등 천연 광물에서 추출하며, 각 안료의 제조 방식이 국가 기밀에 준하는 기술로 전수된다.[3]","detailWlb":{"wlb":"보통이하","social":"보통","wlbDetail":"문화재 보수 현장은 야외 작업이 많고 기후에 영향을 받는다. 문화재 특성상 작업 기간이 길고 세밀한 집중력이 지속 요구된다.","socialDetail":"우리 민족의 건축 문화를 보존하는 소명감이 있으며, 완성된 문화재를 통해 수백 년 뒤에도 남는 작품을 만든다는 자부심이 있다."},"detailReady":{"curriculum":["전통건축학과 입학 또는 문화재 전수교육 이수","한식목구조·단청·석공 실습 과정 수강","전통건축 관련 법규·기준 학습"],"recruit":["문화재 전문 건설사 기능원 채용","문화재청 문화재 보수 용역 사업 참여","국가무형문화재 전수교육관 소속"],"training":["목조건축산업기사·기사 취득","전통건축기능사 자격 취득","문화재수리기술자 자격 도전"]},"sidebarJobs":["건축목공","건축석공","경량철골공","전통건축원","조적원","철골공","철근공","콘크리트공"],"sidebarMajors":["건축학과","건축공학과","건축과","건설공학교육과","건설정보과"],"sidebarCerts":["전통건축기능사","목조건축산업기사","문화재수리기술자","단청기능사","목공예기능사"],"heroTags":["전통건축기능원","전통건축","한옥","문화재복원","목수","전통목공"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"한국전통문화대학교","url":"https://www.nuch.ac.kr/"},{"id":2,"text":"문화재청","url":"https://www.cha.go.kr/"},{"id":3,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"overviewSalary.sal":[{"id":4,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":5,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewProspect.main":[{"id":6,"text":"문화재청","url":"https://www.cha.go.kr/"},{"id":7,"text":"한국고용정보원","url":"https://www.keis.or.kr/"}],"trivia":[{"id":8,"text":"문화재청 한옥기술개발사업단","url":"https://www.cha.go.kr/"},{"id":9,"text":"문화재청 복원사업 백서","url":"https://www.cha.go.kr/"},{"id":10,"text":"국립무형유산원","url":"https://www.nihc.go.kr/"}],"detailWlb.wlbDetail":[{"id":11,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"detailWlb.socialDetail":[{"id":12,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283494451924';
UPDATE jobs SET user_contributed_json = '{"way":"항공정비사가 되려면 항공정비 관련 학과를 졸업하거나 직업훈련기관에서 교육을 이수해야 한다.[1] 국토교통부 항공정비사 면장 취득이 필수이며, 대한항공·아시아나 등 항공사 공채에 응시하는 것이 주된 경로이다.[2] 군 항공 정비 특기병으로 복무한 뒤 전역하여 민간 항공사에 취업하는 방법도 있다.[3]","overviewSalary":{"sal":"대형 항공사 항공기정비원의 평균 연봉은 약 5,000만~7,000만 원이며[1], 숙련된 면장 보유자는 8,000만 원 이상도 가능하다.[2]","source":"커리어넷 직업백과, 워크넷(2024)"},"overviewProspect":{"main":"항공 여객 수요 회복과 저비용 항공사(LCC) 확대로 항공기정비원 수요는 증가 추세이다.[1] 드론·UAM(도심항공교통) 등 신규 항공 모빌리티의 등장도 새로운 정비 인력 수요를 창출하고 있다.[2]","source":"국토교통부, 한국고용정보원(2024)"},"trivia":"항공기 한 대를 유지하기 위해 연간 수천 시간의 정비 작업이 수행된다.[1] 항공기 정비 기록은 단 하나라도 누락되면 운항 금지 조치가 내려질 만큼 기록 관리가 엄격하다.[2] 보잉747 항공기의 부품 수는 약 600만 개에 달하며, 정비원은 모든 시스템에 정통해야 한다.[3]","detailWlb":{"wlb":"보통이하","social":"보통","wlbDetail":"항공기 운항 스케줄에 맞춰 야간·새벽·휴일 근무가 빈번하다. 정밀 작업의 연속으로 집중력 유지에 따른 정신적 피로가 크다.","socialDetail":"수백 명의 안전을 책임지는 항공 안전의 최전선에서 일하며, 항공기 안전 운항에 기여한다는 자부심이 매우 높다."},"detailReady":{"curriculum":["항공정비학과 또는 항공우주공학과 진학","항공기관·기체·전자계통 이론 학습","항공사 연계 인턴·실습 과정 이수"],"recruit":["대형 항공사(대한항공·아시아나·에어부산 등) 공채","저비용항공사(LCC) 수시 채용","MRO(항공정비전문업체) 입사"],"training":["항공정비사 면장 취득(국토교통부)","항공기체·기관·전자기기 자격증 취득","드론 정비 관련 자격 취득"]},"sidebarJobs":["선박정비원","오토바이정비원","자동차정비원","자전거판매 및 정비원","철도기관차·전동차정비원"],"sidebarMajors":["항공정비과","항공우주공학과","항공학과","기계공학과","기계과"],"sidebarCerts":["항공정비사면장","항공산업기사","항공기체기능사","항공기관기능사","드론정비기능사"],"heroTags":["항공기정비원","항공정비사","항공기면장","항공사취업","정비사","항공정비학과"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"국토교통부 항공정책실","url":"https://www.molit.go.kr/"},{"id":3,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"overviewSalary.sal":[{"id":4,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"overviewProspect.main":[{"id":6,"text":"국토교통부","url":"https://www.molit.go.kr/"},{"id":7,"text":"한국고용정보원","url":"https://www.keis.or.kr/"}],"trivia":[{"id":8,"text":"한국항공우주산업진흥협회","url":"https://www.aerospace.or.kr/"},{"id":9,"text":"국토교통부 항공안전","url":"https://www.molit.go.kr/"},{"id":10,"text":"Boeing Technical Overview","url":"https://www.boeing.com/"}],"detailWlb.wlbDetail":[{"id":11,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"detailWlb.socialDetail":[{"id":12,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283398495876';
UPDATE jobs SET user_contributed_json = '{"way":"건설 또는 토목 관련 학과를 졸업하고 현장 경력을 충분히 쌓아야 한다.[1] 건설기사 및 건설관리 관련 자격 취득 후 현장소장이나 공사관리자로 승진하는 것이 일반적인 경로이다.[2] 광업·채굴 분야는 화약류관리기사 등 특수 자격을 갖추어야 관리직에 진입할 수 있다.[3]","overviewSalary":{"sal":"평균 연봉은 약 5,000만~8,000만 원이며[1], 대형 건설사 현장소장은 1억 원 이상도 가능하다.[2]","source":"워크넷 직업정보, 커리어넷(2024)"},"overviewProspect":{"main":"건설 경기에 직접적으로 영향을 받으나[1], 사회 인프라 유지·보수 수요가 지속적으로 있어 전문 관리자 수요는 안정적이다.[2]","source":"한국고용정보원(2024)"},"trivia":"건설·채굴관리자는 수백 명의 현장 인력을 통솔하며 공기·원가·품질·안전 4대 관리를 동시에 수행한다.[1] 채굴 현장에서는 발파 계획 수립부터 안전 점검까지 모두 관리자 책임 하에 진행된다.[2] 해외 건설 현장에 파견된 한국인 건설관리자는 전 세계 120개국 이상에서 활동 중이다.[3]","detailWlb":{"wlb":"보통이하","social":"보통","wlbDetail":"공사 마감 기한에 맞춰 야근과 휴일 근무가 빈번하며, 현장 순회와 다양한 이해관계자 관리로 신체·정신 피로도가 높다.","socialDetail":"도로·건물·인프라를 완성해 도시와 지역사회를 만든다는 자부심이 크며, 완성된 건축물이 수십 년간 사용된다는 성취감이 있다."},"detailReady":{"curriculum":["토목·건축·건설관리학과 전공 선택","건설현장 인턴·실습 경험 축적","건설관련 법규 및 안전 기준 학습"],"recruit":["대형 건설사 현장관리직 공채 응시","전문 건설사 경력직 관리자 채용","공기업(LH·한국도로공사 등) 입사"],"training":["토목시공기술사 자격 도전","건설안전기사 취득","건설기술인 역량강화 교육 이수"]},"sidebarJobs":["건설·광업기계설치·정비원","건설·채굴단순종사원","전기·가스·수도관리자","제조·생산관리자"],"sidebarMajors":["건축공학과","토목공학과","건설공학교육과","도시건설과","건설정보과"],"sidebarCerts":["건설기사","토목기사","건축기사","건설관리기사","화약류관리기사"],"heroTags":["건설채굴관리자","현장소장","건설관리자","채굴관리","건설기사","토목기사"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":3,"text":"대한건설협회","url":"https://www.cak.or.kr/"}],"overviewSalary.sal":[{"id":4,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":5,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewProspect.main":[{"id":6,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":7,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"trivia":[{"id":8,"text":"대한건설협회","url":"https://www.cak.or.kr/"},{"id":9,"text":"화약류 안전관리법령","url":"https://www.law.go.kr/"},{"id":10,"text":"해외건설협회","url":"https://www.icak.or.kr/"}],"detailWlb.wlbDetail":[{"id":11,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"detailWlb.socialDetail":[{"id":12,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283412658784';
